// https://github.com/npm/npm/blob/latest/lib/config/core.js#L362-L407
export function parseField(input: any, key: string | number) {
  if (typeof input !== "string") {
    return input;
  }

  const typeList: any[] = [].concat(types[key]);
  const isPath = typeList.indexOf(path) !== -1;
  const isBool = typeList.indexOf(Boolean) !== -1;
  const isString = typeList.indexOf(String) !== -1;
  const isNumber = typeList.indexOf(Number) !== -1;

  let field = `${input}`.trim();

  if (/^".*"$/.test(field)) {
    try {
      field = JSON.parse(field);
    } catch (err) {
      throw new Error(`Failed parsing JSON config key ${key}: ${field}`);
    }
  }

  if (isBool && !isString && field === "") {
    return true;
  }

  switch (field) {
    case "true": {
      return true;
    }

    case "false": {
      return false;
    }

    case "null": {
      return null;
    }

    case "undefined": {
      return undefined;
    }

    // no default
  }

  field = envReplace(field);

  if (isPath) {
    const regex = process.platform === "win32" ? /^~(\/|\\)/ : /^~\//;

    if (regex.test(field) && process.env["HOME"]) {
      field = path.resolve(process.env["HOME"], field.substr(2));
    }

    field = path.resolve(field);
  }

  // TODO: refactor based on TS feedback
  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
  // @ts-ignore
  if (isNumber && !Number.isNaN(field)) {
    // TODO: refactor based on TS feedback
    // eslint-disable-next-line @typescript-eslint/ban-ts-comment
    // @ts-ignore
    field = Number(field);
  }

  return field;
}

import { getProjectItems } from '../support/app.po';

describe('watch mode  - app', () => {
  beforeEach(() => {
    cy.visit('/projects');
  });

  it('should auto-select new libs as they are created', () => {
    const excludedValues = ['existing-app-1', 'existing-lib-1'];
    checkSelectedProjects(2, excludedValues);
    checkSelectedProjects(3, excludedValues);
    checkSelectedProjects(4, excludedValues);
  });

  it('should retain selected projects as new libs are created', () => {
    cy.get('[data-project="existing-app-1"]').click();
    cy.get('[data-project="existing-lib-1"]').click();

    checkSelectedProjects(3, []);
    checkSelectedProjects(4, []);
    checkSelectedProjects(5, []);
  });

  it('should not re-add new libs if they were un-selected', () => {
    cy.get('[data-project*="3"][data-active="true"]', { timeout: 6000 })
      .should('exist')
      .click({ force: true });

    cy.get('[data-project*="3"][data-active="false"]', {
      timeout: 6000,
    }).should('exist');

    cy.get('[data-project*="3"]', { timeout: 6000 })
      .first()
      .should((project) => {
        expect(project.data('active')).to.be.false;
      });
  });
});

function checkSelectedProjects(
  expectedNumberOfProjects: number,
  excludedProjects: string[]
) {
  getProjectItems().should((projects) => {
    expect(projects.length).to.equal(expectedNumberOfProjects);
    projects.each(function () {
      if (!excludedProjects.includes(this.dataset.project)) {
        expect(this.dataset.active).to.eq('true');
      }
    });
  });
}

import { readdirSync, rmSync, statSync } from 'fs';
import { join } from 'path';

const WEEK_IN_MS = 1000 * 60 * 60 * 24 * 7;

const folder = process.argv[2];

removeOld(terminalOutputs());
removeOld(cachedFiles());

function terminalOutputs() {
  try {
    return readdirSync(join(folder, 'terminalOutputs')).map((f) =>
      join(folder, 'terminalOutputs', f)
    );
  } catch (e) {
    return [];
  }
}

function cachedFiles() {
  try {
    return readdirSync(folder)
      .filter((f) => !f.endsWith('terminalOutputs'))
      .map((f) => join(folder, f));
  } catch (e) {
    return [];
  }
}

function removeOld(records: string[]) {
  try {
    const time = mostRecentMTime(records);

    records.forEach((r) => {
      try {
        const s = statSync(r);
        if (time - s.mtimeMs > WEEK_IN_MS) {
          if (s.isDirectory()) {
            try {
              rmSync(`${r}.commit`, { recursive: true, force: true });
            } catch (e) {}
          }
          rmSync(r, { recursive: true, force: true });
        }
      } catch (e) {}
    });
  } catch (e) {}
}

function mostRecentMTime(records: string[]) {
  let mostRecentTime = 0;
  records.forEach((r) => {
    try {
      const s = statSync(r);
      if (s.mtimeMs > mostRecentTime) {
        mostRecentTime = s.mtimeMs;
      }
    } catch (e) {}
  });
  return mostRecentTime;
}

import { logger } from '@nx/devkit';
import * as net from 'net';

export function waitForPortOpen(
  port: number,
  options: { host?: string; retries?: number; retryDelay?: number } = {}
): Promise<void> {
  const host = options.host ?? '127.0.0.1';
  const allowedErrorCodes = ['ECONNREFUSED', 'ECONNRESET', 'ETIMEDOUT'];

  return new Promise((resolve, reject) => {
    const checkPort = (retries = options.retries ?? 120) => {
      const client = new net.Socket();
      const cleanupClient = () => {
        client.removeAllListeners('connect');
        client.removeAllListeners('error');
        client.end();
        client.destroy();
        client.unref();
      };
      client.once('connect', () => {
        cleanupClient();
        resolve();
      });

      client.once('error', (err) => {
        if (retries === 0 || !allowedErrorCodes.includes(err['code'])) {
          if (process.env['NX_VERBOSE_LOGGING'] === 'true') {
            logger.info(
              `Error connecting on ${host}:${port}: ${err['code'] || err}`
            );
          }
          cleanupClient();
          reject(err);
        } else {
          setTimeout(() => checkPort(retries - 1), options.retryDelay ?? 1000);
        }
      });

      // Node will use IPv6 if it is available, but this can cause issues if the server is only listening on IPv4.
      // Hard-coding to look on 127.0.0.1 to avoid using the IPv6 loopback address "::1".
      if (process.env['NX_VERBOSE_LOGGING'] === 'true') {
        logger.info(`Connecting on ${host}:${port}`);
      }
      client.connect({ port, host });
    };

    checkPort();
  });
}

