import type {
  JSONSchema4,
  JSONSchema4Type,
} from '@typescript-eslint/utils/json-schema';

import type { SchemaAST, RefMap, UnionAST } from './types.js';

import { NotSupportedError } from './errors.js';
import { generateType } from './generateType.js';

export function generateUnionType(
  members: (JSONSchema4 | JSONSchema4Type)[],
  refMap: RefMap,
): UnionAST {
  const elements: SchemaAST[] = [];

  for (const memberSchema of members) {
    elements.push(
      ((): SchemaAST => {
        switch (typeof memberSchema) {
          case 'string':
            return {
              code: `'${memberSchema.replaceAll("'", "\\'")}'`,
              commentLines: [],
              type: 'literal',
            };

          case 'number':
          case 'boolean':
            return {
              code: `${memberSchema}`,
              commentLines: [],
              type: 'literal',
            };

          case 'object':
            if (memberSchema == null) {
              throw new NotSupportedError('null in an enum', memberSchema);
            }
            if (Array.isArray(memberSchema)) {
              throw new NotSupportedError('array in an enum', memberSchema);
            }
            return generateType(memberSchema, refMap);
        }
      })(),
    );
  }

  return {
    commentLines: [],
    elements,
    type: 'union',
  };
}

import { HTTPError, type H3Event, type HTTPEvent } from "h3";
import type { InternalHandlerResponse } from "./utils.ts";
import { FastResponse } from "srvx";
import type { NitroErrorHandler } from "nitro/types";

const errorHandler: NitroErrorHandler = (error, event) => {
  const res = defaultHandler(error, event);
  return new FastResponse(
    typeof res.body === "string" ? res.body : JSON.stringify(res.body, null, 2),
    res
  );
};

export default errorHandler;

export function defaultHandler(error: HTTPError, event: HTTPEvent): InternalHandlerResponse {
  const unhandled = error.unhandled ?? !HTTPError.isError(error);
  const { status = 500, statusText = "" } = unhandled ? {} : error;

  if (status === 404) {
    const url = (event as H3Event).url || new URL(event.req.url);
    const baseURL = import.meta.baseURL || "/";
    if (/^\/[^/]/.test(baseURL) && !url.pathname.startsWith(baseURL)) {
      return {
        status: 302,
        headers: new Headers({ location: `${baseURL}${url.pathname.slice(1)}${url.search}` }),
      };
    }
  }

  const headers = new Headers(unhandled ? {} : error.headers);
  headers.set("content-type", "application/json; charset=utf-8");

  const jsonBody = unhandled
    ? { status, unhandled: true }
    : typeof error.toJSON === "function"
      ? error.toJSON()
      : { status, statusText, message: error.message };

  return {
    status,
    statusText,
    headers,
    body: {
      error: true,
      ...jsonBody,
    },
  };
}

